function hasIssue(row) {
    if (!row.last_reading) return true;
    try {
        const lastReading = new Date(row.last_reading);
        const now = new Date();
        const hoursDiff = (now - lastReading) / (1000 * 60 * 60); // Convert ms to hours
        return hoursDiff > 72;
    } catch (e) {
        return true; // Treat invalid dates as issues
    }
}

